          "jsCode": "// Initialize Execution Context
const input = $input.all()[0].json;

// Generate unique execution ID
const execution_id = `exec_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

// Extract data from Airtable trigger - handle both content specs and WP posts
const record_id = input.id || input.fields?.id;

// Try multiple field names for topic
const topic = input.fields?.Topic 
  || input.fields?.topic 
  || input.fields?.title_html 
  || input.Topic 
  || input.title;

const audience = input.fields?.['Target Audience'] 
  || input.fields?.audience 
  || input.fields?.Audience
  || 'General audience';

const language = input.fields?.Language 
  || input.fields?.language 
  || input.fields?.lang
  || 'en';

const word_count = parseInt(
  input.fields?.['Word Count'] 
  || input.fields?.word_count 
  || input.fields?.Word_Count
  || 1500
);

const keywords = input.fields?.Keywords 
  || input.fields?.keywords 
  || '';

const status = input.fields?.Status 
  || input.fields?.status 
  || '';

// Create execution context
const context = {
  execution_id: execution_id,
  record_id: record_id,
  topic: topic,
  audience: audience,
  language: language,
  word_count: word_count,
  keywords: keywords,
  status: status,
  phase: 'initialization',
  created_at: new Date().toISOString(),
  memory_key: `content_${record_id}`,
  tokens_used: {
    planning: 0,
    content: 0,
    validation: 0,
    total: 0
  }
};

// Save to workflow static data for recovery
const staticData = $getWorkflowStaticData('global');
staticData.current_execution = execution_id;
staticData.current_record = record_id;

console.log('🚀 Execution initialized:', execution_id);
console.log('📝 Topic:', context.topic);
console.log('🎯 Target:', context.word_count, 'words');
console.log('👥 Audience:', context.audience);

// Validation check
if (!context.topic || context.topic.trim() === '') {
  console.error('❌ ERROR: Topic field is missing!');
  console.log('Available fields:', Object.keys(input.fields || {}));
}

return [{ json: context }];"
