          "mode": "runOnceForEachItem",
          "jsCode": "// Prepare Research Context for Planning Agent
const input = $input.item.json;

// Create minimal context for research phase
const research_context = {
  execution_id: input.execution_id,
  record_id: input.record_id,
  topic: input.topic,
  audience: input.audience,
  language: input.language,
  word_count_target: input.word_count,
  keywords_raw: input.keywords,
  keywords_array: input.keywords 
    ? input.keywords.split(',').map(k => k.trim()).filter(k => k).slice(0, 5) 
    : [],
  memory_key: input.memory_key,
  phase: 'planning'
};

// Create AI prompt for planning agent
const planning_prompt = `
CONTENT PLANNING & RESEARCH REQUEST

**Topic:** "${research_context.topic}"
**Target Audience:** ${research_context.audience}
**Language:** ${research_context.language}
**Target Word Count:** ${research_context.word_count_target} words
**Focus Keywords:** ${research_context.keywords_array.join(', ') || 'None provided'}

YOUR TASK:
You are a Content Research & Strategy AI Agent. Create a comprehensive content plan.

RESEARCH STEPS:
1. Use Tavily to research current trends, statistics, and information about this topic
2. Search WordPress for similar existing content to avoid duplication
3. Search Airtable for related content specifications to maintain consistency
4. Analyze competitor content and identify gaps
5. Determine the search intent (informational, commercial, navigational, transactional)

STRATEGY REQUIREMENTS:
- Develop a unique angle that differentiates from existing content
- Create a detailed outline with H2 and H3 structure
- Identify primary and secondary keywords
- Plan internal linking opportunities
- Consider user search intent and journey
- Include credible external sources to reference

DELIVERABLES:
Return a complete JSON with:
- Overall content strategy and unique angle
- Search intent analysis
- Detailed outline (H2 sections with H3 subsections)
- SEO keyword recommendations (primary, secondary, long-tail)
- Internal linking suggestions
- Research sources and key insights
- Competitive gap analysis
- Estimated reading time

Focus on creating content that provides REAL VALUE to ${research_context.audience}.
`;

console.log('📋 Planning phase starting');
console.log('🔍 Research topic:', research_context.topic);

return {
  json: {
    ...research_context,
    prompt: planning_prompt
  }
};"
