      {
        "parameters": {
          "jsCode": "// Compress & Save Planning Data - COMPLETE VERSION
const input = $input.item.json;

// Get context from previous node
let execution_id, record_id, topic, audience, language, word_count, memory_key;

try {
  const prep_context = $('Code: Prep Context').first().json;
  execution_id = prep_context.execution_id;
  record_id = prep_context.record_id;
  topic = prep_context.topic;
  audience = prep_context.audience;
  language = prep_context.language;
  word_count = prep_context.word_count_target;
  memory_key = prep_context.memory_key;
} catch (e) {
  // Fallback to input if can't reach previous node
  execution_id = input.execution_id || 'unknown';
  record_id = input.record_id || 'unknown';
  topic = input.topic || '';
  audience = input.audience || 'General audience';
  language = input.language || 'en';
  word_count = input.word_count || 1500;
  memory_key = input.memory_key || `content_${record_id}`;
}

// Extract planning data from AI Agent output
let planning_output;
if (input.output) {
  // AI Agent wraps response in .output
  planning_output = input.output;
} else if (input.strategy) {
  // Already flat structure
  planning_output = input;
} else {
  // Unexpected structure
  console.error('Unexpected input structure:', Object.keys(input));
  planning_output = {};
}

// Create FLAT data structure for Data Table
const flat_plan = {
  execution_id: String(execution_id),
  record_id: String(record_id),
  phase: 'planning',

  // Original specs - CRITICAL for next phases
  topic: String(topic),
  audience: String(audience),
  language: String(language),
  word_count: Number(word_count),
  memory_key: String(memory_key),

  // Planning phase output
  strategy: String(planning_output.strategy || ''),
  target_search_intent: String(planning_output.target_search_intent || ''),
  competitive_gap: String(planning_output.competitive_gap || ''),
  estimated_time: String(planning_output.estimated_time || ''),

  // Stringify complex objects for Data Table storage
  outline_json: JSON.stringify(planning_output.outline || {}),
  seo_keywords_json: JSON.stringify(planning_output.seo_keywords || {}),
  internal_links_json: JSON.stringify(planning_output.internal_links || []),
  research_sources_json: JSON.stringify(planning_output.research_sources || []),

  // Metadata
  tokens_estimate: 4000,
  completed_at: new Date().toISOString()
};

// Debug logging
console.log('✅ Planning phase data prepared');
console.log('🔑 Execution ID:', flat_plan.execution_id);
console.log('📋 Record ID:', flat_plan.record_id);
console.log('📝 Topic:', flat_plan.topic);
console.log('👥 Audience:', flat_plan.audience);
console.log('🌐 Language:', flat_plan.language);
console.log('📊 Word Count Target:', flat_plan.word_count);
console.log('💾 Strategy length:', flat_plan.strategy.length, 'chars');
console.log('📦 Outline JSON length:', flat_plan.outline_json.length, 'chars');

// Validate critical fields before returning
if (!flat_plan.execution_id || flat_plan.execution_id === 'unknown') {
  throw new Error('Missing execution_id - check data flow from Code: Init');
}

if (!flat_plan.topic || flat_plan.topic === '') {
  throw new Error('Missing topic - check data flow from Code: Prep Context');
}

return { json: flat_plan };"
