          "jsCode": "// Load Context from Data Table OR Regeneration
const input = $input.item.json;

console.log('📥 Loading context for content creation');
console.log('🔍 Input keys:', Object.keys(input));

// Check if this is a regeneration attempt
if (input.is_regeneration) {
  console.log('🔄 REGENERATION MODE - Attempt', input.attempt_count);

  // For regeneration, we need to fetch the planning data from Data Table
  // But we already have the core context from the regen prep node

  const regeneration_context = {
    execution_id: input.execution_id,
    record_id: input.record_id,
    topic: input.topic,
    audience: input.audience,
    language: input.language,
    word_count: input.word_count,
    memory_key: input.memory_key,
    phase: 'content_creation_regen'
  };

  // Create enhanced prompt with regeneration feedback
  const content_prompt = `
⚠️ REGENERATION REQUEST - ATTEMPT ${input.attempt_count}/3 ⚠️

PREVIOUS ATTEMPT PERFORMANCE:
- Quality Score: ${input.previous_score}/10
- Status: REJECTED

${input.regeneration_feedback}

---

NOW, CREATE IMPROVED CONTENT:

**Topic:** "${input.topic}"
**Target Audience:** ${input.audience}
**Language:** ${input.language}
**Target Word Count:** ${input.word_count} words

YOUR TASK:
You are an expert Content Creator AI. Create SIGNIFICANTLY IMPROVED content that addresses ALL the feedback above.

CRITICAL REQUIREMENTS:
1. Fix EVERY issue mentioned in the feedback
2. Implement ALL improvement suggestions
3. Address the human reviewer's specific feedback
4. Ensure this version is demonstrably better than the previous attempt
5. Do not repeat the same mistakes

CONTENT CREATION STEPS:
1. Search WordPress for similar existing posts to understand style
2. Review Airtable for related content to maintain consistency
3. Create engaging, original content
4. Use proper WordPress Gutenberg block structure
5. Target ${input.word_count} words (±10%)

DELIVERABLES:
Return complete JSON with:
- SEO-optimized title (50-60 characters)
- Meta description (150-160 characters)
- URL-friendly slug
- Full HTML content with Gutenberg blocks
- SEO data (keywords used, density, readability)
- Internal and external links
- Content metadata (word count, reading time, structure)

This is attempt ${input.attempt_count} of 3. Make it EXCELLENT!
`;

  console.log('✅ Regeneration prompt created');
  console.log('📊 Previous score:', input.previous_score);
  console.log('🔢 Attempt:', input.attempt_count, '/ 3');

  return {
    json: {
      ...regeneration_context,
      prompt: content_prompt,
      is_regeneration: true,
      attempt_count: input.attempt_count
    }
  };
}

// ORIGINAL PATH: First-time content creation from planning data
console.log('✨ FIRST-TIME CONTENT CREATION');

// The input is the planning row from Insert row node
const planning_row = input;

// Parse JSON strings back to objects
let outline, seo_keywords, internal_links, research_sources;

try {
  outline = JSON.parse(planning_row.outline_json);
  seo_keywords = JSON.parse(planning_row.seo_keywords_json);
  internal_links = JSON.parse(planning_row.internal_links_json);
  research_sources = JSON.parse(planning_row.research_sources_json);
} catch (e) {
  console.error('❌ Failed to parse planning data:', e.message);
  throw new Error('Invalid planning data format');
}

// Create compressed context
const context = {
  execution_id: planning_row.execution_id,
  record_id: planning_row.record_id,

  // Strategy summary (first 250 chars)
  strategy_summary: planning_row.strategy.substring(0, 250) + '...',

  // Outline summary
  outline_themes: outline.h2_sections.map(s => s.heading),
  h2_count: outline.h2_sections.length,
  introduction_guide: outline.introduction,
  conclusion_guide: outline.conclusion,

  // Keywords
  primary_keyword: seo_keywords.primary,
  secondary_keywords: seo_keywords.secondary.slice(0, 3),
  long_tail_keywords: seo_keywords.long_tail.slice(0, 3),

  // Key points
  key_points: outline.h2_sections
    .flatMap(s => s.key_points || [])
    .slice(0, 12),

  // Planning data
  competitive_gap: planning_row.competitive_gap,
  research_insights: research_sources
    .slice(0, 3)
    .map(r => r.key_insight),

  // Original specs from planning_row
  topic: planning_row.topic,
  audience: planning_row.audience,
  language: planning_row.language,
  word_count: planning_row.word_count,
  memory_key: planning_row.memory_key,

  phase: 'content_creation'
};

// Create content generation prompt
const content_prompt = `
CONTENT GENERATION REQUEST

**Topic:** "${context.topic}"
**Target Audience:** ${context.audience}
**Language:** ${context.language}
**Target Word Count:** ${context.word_count} words
**Primary Keyword:** ${context.primary_keyword}
**Secondary Keywords:** ${context.secondary_keywords.join(', ')}

STRATEGY CONTEXT:
${context.strategy_summary}

COMPETITIVE ADVANTAGE:
${context.competitive_gap}

OUTLINE STRUCTURE (Create ${context.h2_count} main sections):
${context.outline_themes.map((theme, i) => `${i + 1}. ${theme}`).join('\\n')}

INTRODUCTION GUIDANCE:
${context.introduction_guide}

CONCLUSION GUIDANCE:
${context.conclusion_guide}

MUST INCLUDE THESE KEY POINTS:
${context.key_points.map((p, i) => `• ${p}`).join('\\n')}

RESEARCH INSIGHTS TO INCORPORATE:
${context.research_insights.map((insight, i) => `• ${insight}`).join('\\n')}

YOUR TASK:
You are an expert Content Creator AI. Write comprehensive, engaging content.

CONTENT CREATION STEPS:
1. Search WordPress for similar existing posts to understand style and reference
2. Review Airtable for related content to maintain consistency
3. Create engaging, original content following the outline structure
4. Use proper WordPress Gutenberg block structure
5. Naturally incorporate all keywords without keyword stuffing
6. Include internal linking opportunities
7. Write in ${context.language} language with appropriate tone for ${context.audience}
8. Target ${context.word_count} words (±10%)

DELIVERABLES:
Return complete JSON with:
- SEO-optimized title (50-60 characters)
- Meta description (150-160 characters)
- URL-friendly slug
- Full HTML content with Gutenberg blocks
- SEO data (keywords used, density, readability)
- Internal and external links
- Content metadata (word count, reading time, structure)
- Quality indicators

Make this content the BEST resource on "${context.topic}" for ${context.audience}.
`;

console.log('📝 Content creation starting');
console.log('🎯 Target:', context.word_count, 'words');
console.log('📋 Structure:', context.h2_count, 'main sections');
console.log('🔑 Primary keyword:', context.primary_keyword);

return {
  json: {
    ...context,
    prompt: content_prompt
  }
};"
