const content = $('Code: Process').first().json;
const init = $('Code: Init').first().json;

// Calculate final metrics
const execution_start = new Date(init.created_at);
const execution_end = new Date();
const total_time_ms = execution_end - execution_start;
const total_time_minutes = Math.round(total_time_ms / 1000 / 60);
const total_time_seconds = Math.round(total_time_ms / 1000);

// Calculate token usage
const tokens_used = {
  planning: planning.tokens_estimate || 4000,
  content: content.tokens_estimate || 12000,
  validation: 3000,
  total: (planning.tokens_estimate || 4000) + (content.tokens_estimate || 12000) + 3000
};

// Estimate cost (OpenAI GPT-4 pricing - adjust for your model)
const cost_per_1k_tokens = 0.03; // Adjust based on your model
const estimated_cost = (tokens_used.total / 1000) * cost_per_1k_tokens;

// Create comprehensive final report
const final_report = {
  execution_id: content.execution_id,
  record_id: content.record_id,
  status: 'completed',

  // Results
  wordpress_url: wordpress.link || wordpress.guid?.rendered,
  wordpress_id: wordpress.id,
  wordpress_status: wordpress.status,

  // Content metrics
  title: validation.title,
  slug: validation.slug,
  word_count: content.metadata?.word_count || 0,
  reading_time: content.metadata?.reading_time || 0,

  // Quality metrics
  quality_score: validation.quality_score || 8.5,
  validation_results: validation.validation_results || {},

  // SEO metrics
  primary_keyword: content.seo_data?.focus_keyword || 'unknown',
  keyword_density: content.seo_data?.keyword_density || 0,
  readability_score: content.seo_data?.readability_score || 0,

  // Links
  internal_links: content.internal_links?.length || 0,
  external_links: content.external_links?.length || 0,

  // Performance
  total_time_minutes: total_time_minutes,
  total_time_seconds: total_time_seconds,

  // Token usage & cost
  tokens_used: tokens_used,
  estimated_cost_usd: estimated_cost.toFixed(4),

  // Phases completed
  phases: {
    initialization: 'completed',
    planning: 'completed',
    content_creation: 'completed',
    validation: 'completed',
    publishing: 'completed'
  },

  // Performance estimates
  performance_potential: validation.performance || 'Good',

  // Timestamps
  started_at: init.created_at,
  completed_at: execution_end.toISOString()
};

// Clear workflow static data
const staticData = $getWorkflowStaticData('global');
delete staticData.current_execution;
delete staticData.current_record;

console.log('🎉 ========================================');
console.log('🎉 WORKFLOW COMPLETED SUCCESSFULLY!');
console.log('🎉 ========================================');
console.log('');
console.log('📊 EXECUTION SUMMARY:');
