    // Fix 1: Unterminated strings
    const unterminatedPattern = /"([^"]*?)(?:\n|$)/g;
    let fixedCount = 0;
    fixedJson = fixedJson.replace(unterminatedPattern, (match, content) => {
      if (!match.endsWith('"')) {
        fixedCount++;
        return `"${content}"`;
      }
      return match;
    });

    if (fixedCount > 0) {
      fixesApplied.push(`Fixed ${fixedCount} unterminated strings`);
      console.log(`✅ Fixed ${fixedCount} unterminated strings`);
    }

    // Fix 2: Trailing commas
    const trailingCommaPattern = /,(\s*[}\]])/g;
    const beforeTrailing = fixedJson;
    fixedJson = fixedJson.replace(trailingCommaPattern, '$1');

    if (fixedJson !== beforeTrailing) {
      fixesApplied.push('Fixed trailing commas');
      console.log('✅ Fixed trailing commas');
    }

    // Fix 3: Missing brackets
    const openBraces = (fixedJson.match(/\{/g) || []).length;
    const closeBraces = (fixedJson.match(/\}/g) || []).length;
    const openBrackets = (fixedJson.match(/\[/g) || []).length;
    const closeBrackets = (fixedJson.match(/\]/g) || []).length;

    let bracketFixes = 0;
    if (openBraces > closeBraces) {
      const missing = openBraces - closeBraces;
      fixedJson += '}'.repeat(missing);
      bracketFixes += missing;
    }

    if (openBrackets > closeBrackets) {
      const missing = openBrackets - closeBrackets;
      fixedJson += ']'.repeat(missing);
      bracketFixes += missing;
    }

    if (bracketFixes > 0) {
      fixesApplied.push(`Added ${bracketFixes} missing brackets`);
      console.log(`✅ Added ${bracketFixes} missing brackets`);
    }

    // Try to parse the fixed JSON
    try {
      const parsed = JSON.parse(fixedJson);
      console.log('✅ JSON fixed successfully');
      return { 
        valid: true, 
        fixed: true, 
        data: parsed, 
        fixesApplied
      };
    } catch (finalError) {
      console.log('❌ Could not fix JSON:', finalError.message);
      return { 
        valid: false, 
        fixed: false, 
        error: finalError.message,
        fixesApplied
      };
    }
  }
}

// Validate and fix the content
const result = validateAndFixJson(contentToValidate);

if (result.valid) {
  console.log('✅ JSON validation successful');
  console.log('📊 Fixes applied:', result.fixesApplied);
  console.log('📊 Final data keys:', Object.keys(result.data || {}));

  // Return the fixed data
  return { json: result.data };
} else {
  console.log('❌ JSON validation failed');
  console.log('📊 Error:', result.error);
  console.log('📊 Fixes attempted:', result.fixesApplied);

  // Return error information
  return { 
    json: {
      error: 'JSON validation failed',
      originalError: result.error,
      fixesAttempted: result.fixesApplied,
      rawOutput: contentToValidate.substring(0, 500) + '...'
    }
  };
